import React, { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";
import { LayoutDashboard, AlertTriangle, Network, MessageSquare, LogOut, Settings, Menu, X } from "lucide-react";
import { cn } from "@/lib/utils";
import { AIChat } from "@/components/ui/ai-chat";
import { MenuVertical } from "@/components/ui/menu-vertical";
import { motion, AnimatePresence } from "framer-motion";

const SidebarItem = ({ icon: Icon, label, href, active, gradient, iconColor }: any) => (
  <Link
    to={href}
    className={cn(
      "relative flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 overflow-hidden group mb-2 cursor-pointer",
      active ? "bg-white/5 border border-white/10" : "hover:bg-white/5 transparent"
    )}
  >
    {active && (
      <div
        className="absolute inset-0 opacity-20 transition-opacity duration-300 pointer-events-none"
        style={{ background: gradient }}
      ></div>
    )}
    <div className={cn(
      "flex items-center justify-center relative z-10 transition-colors duration-300",
      active ? iconColor : "text-on-surface-variant group-hover:text-on-surface"
    )}>
      <Icon className="w-5 h-5" />
    </div>
    <span className={cn(
      "font-medium text-sm z-10 transition-colors duration-300",
      active ? "text-on-surface" : "text-on-surface-variant group-hover:text-on-surface"
    )}>
      {label}
    </span>
  </Link>
);

export function DashboardLayout({ children }: { children: React.ReactNode }) {
  const location = useLocation();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Close mobile menu on route change
  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [location.pathname]);

  const navigation = [
    { icon: LayoutDashboard, label: "Overview", href: "/dashboard", gradient: "radial-gradient(circle, rgba(59,130,246,0.15) 0%, rgba(37,99,235,0.06) 50%, rgba(29,78,216,0) 100%)", iconColor: "text-blue-400" },
    { icon: AlertTriangle, label: "Violations", href: "/violations", gradient: "radial-gradient(circle, rgba(239,68,68,0.15) 0%, rgba(220,38,38,0.06) 50%, rgba(185,28,28,0) 100%)", iconColor: "text-red-400" },
    { icon: Network, label: "Knowledge Graph", href: "/graph", gradient: "radial-gradient(circle, rgba(168,85,247,0.15) 0%, rgba(147,51,234,0.06) 50%, rgba(126,34,206,0) 100%)", iconColor: "text-purple-400" },
    { icon: MessageSquare, label: "AI Chatbot", href: "/chat", gradient: "radial-gradient(circle, rgba(34,197,94,0.15) 0%, rgba(22,163,74,0.06) 50%, rgba(21,128,61,0) 100%)", iconColor: "text-green-400" },
  ];

  return (
    <div className="flex h-[100dvh] w-full bg-background text-on-background font-body overflow-hidden selection:bg-primary selection:text-on-primary-container">

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-background/80 backdrop-blur-sm z-40 md:hidden"
            onClick={() => setIsMobileMenuOpen(false)}
          />
        )}
      </AnimatePresence>

      {/* Sidebar */}
      <aside className={cn(
        "w-64 border-r border-outline-variant/30 bg-surface/90 backdrop-blur-xl flex flex-col h-full absolute md:relative z-50 shadow-[4px_0_24px_rgba(0,0,0,0.2)] transition-transform duration-300 left-0 top-0",
        isMobileMenuOpen ? "translate-x-0" : "-translate-x-full md:translate-x-0"
      )}>
        <div className="p-6 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-primary text-primary-foreground rounded-md p-1.5 flex items-center justify-center font-headline font-bold text-xl w-8 h-8">
              A
            </div>
            <span className="text-xl font-bold font-headline tracking-tight text-on-surface">AuditAI</span>
          </div>
          <button
            className="md:hidden text-on-surface-variant hover:text-white"
            onClick={() => setIsMobileMenuOpen(false)}
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="px-2 py-4 flex-grow overflow-y-auto mt-2">
          <p className="px-4 text-[11px] font-bold text-on-surface-variant/70 uppercase tracking-widest mb-4">Core Pipeline</p>
          <div className="space-y-1">
            {navigation.map((item) => (
              <SidebarItem
                key={item.href}
                {...item}
                active={location.pathname === item.href || (location.pathname === '/' && item.href === '/dashboard')}
              />
            ))}
          </div>
        </div>

        <div className="p-4 border-t border-outline-variant/30">
          <Link to="/" className="flex items-center gap-3 px-4 py-3 text-on-surface-variant hover:text-on-surface transition-colors rounded-xl hover:bg-white/5">
            <LogOut className="w-5 h-5" />
            <span className="font-medium text-sm">Sign Out</span>
          </Link>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-full relative z-10">
        {/* Glow ambient background elements for the theme */}
        <div className="absolute top-0 right-0 w-[40rem] h-[40rem] bg-primary/10 rounded-full blur-[120px] pointer-events-none -translate-y-1/2 translate-x-1/3"></div>
        <div className="absolute bottom-0 left-0 w-[40rem] h-[40rem] bg-tertiary/10 rounded-full blur-[120px] pointer-events-none translate-y-1/3 -translate-x-1/3"></div>

        {/* Mobile Header */}
        <header className="md:hidden h-16 border-b border-outline-variant/30 bg-surface/80 backdrop-blur-md flex items-center justify-between px-4 z-20">
          <div className="flex items-center gap-2">
            <div className="bg-primary text-primary-foreground rounded-md p-1 flex items-center justify-center font-headline font-bold text-lg w-7 h-7">A</div>
            <span className="font-headline font-bold text-on-surface">AuditAI</span>
          </div>
          <button
            className="text-on-surface-variant hover:text-on-surface p-2 rounded-lg hover:bg-white/5 transition-colors"
            onClick={() => setIsMobileMenuOpen(true)}
          >
            <Menu className="w-6 h-6" />
          </button>
        </header>

        {/* Scrollable Content Container with Page Transitions */}
        <div className="flex-1 overflow-y-auto overflow-x-hidden w-full relative z-10 flex flex-col">
          <AnimatePresence mode="wait">
            <motion.div
              key={location.pathname}
              initial={{ opacity: 0, scale: 0.98, filter: "blur(4px)" }}
              animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
              exit={{ opacity: 0, scale: 0.98, filter: "blur(4px)" }}
              transition={{ duration: 0.3, ease: "easeInOut" }}
              className="flex-1 w-full h-full"
            >
              {children}
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Global Floating AI Chatbot */}
        <AIChat />
      </main>
    </div>
  );
}

import React, { useState, useRef, useEffect } from "react";
import { MessageSquare, X, Send, Bot, User, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";

export function AIChat() {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState("");
  const [messages, setMessages] = useState<{ role: 'user' | 'ai', content: string }[]>([
    { role: 'ai', content: "Hello! I'm your Explanation Agent powered by Llama 3. Ask me about any flagged transaction or compliance rule." }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setMessages(prev => [...prev, { role: 'user', content: query.trim() }]);
    setQuery("");
    setIsTyping(true);

    // Simulate Agent A4 logic parsing the database
    setTimeout(() => {
      setIsTyping(false);
      setMessages(prev => [...prev, {
        role: 'ai',
        content: "Based on the Validator Agent's rule engine, TXN-8921 was flagged because the offshore entity 'Offshore Tech LLC' is not registered in our approved vendor database (AML Policy 4.2). This results in a HIGH severity penalty risk."
      }]);
    }, 2000);
  };

  return (
    <>
      <AnimatePresence>
        {!isOpen && (
          <motion.button
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0, opacity: 0 }}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
            onClick={() => setIsOpen(true)}
            className="fixed bottom-6 right-6 w-14 h-14 rounded-full bg-primary text-primary-foreground shadow-[0_0_30px_rgba(59,130,246,0.5)] flex items-center justify-center z-50 hover:bg-primary-dark transition-colors"
          >
            <MessageSquare className="w-6 h-6" />
          </motion.button>
        )}
      </AnimatePresence>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            transition={{ type: "spring", bounce: 0.2 }}
            className="fixed bottom-6 right-6 w-[350px] sm:w-[400px] h-[500px] glass-card glass-border rounded-2xl flex flex-col z-50 overflow-hidden shadow-[0_10px_40px_rgba(0,0,0,0.5)] bg-surface/95 backdrop-blur-2xl border border-outline-variant/50"
          >
            {/* Header */}
            <div className="p-4 border-b border-outline-variant/30 flex items-center justify-between bg-primary/10">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center text-primary">
                  <Bot className="w-5 h-5" />
                </div>
                <div>
                  <h3 className="font-headline font-bold text-on-surface text-sm">Explanation Agent</h3>
                  <div className="flex items-center gap-1.5 align-middle">
                    <span className="w-2 h-2 rounded-full bg-green-500 drop-shadow-[0_0_4px_rgba(34,197,94,0.8)]"></span>
                    <span className="text-xs font-semibold text-green-400 capitalize">Groq / Llama 3</span>
                  </div>
                </div>
              </div>
              <button
                onClick={() => setIsOpen(false)}
                className="text-on-surface-variant hover:text-white transition-colors p-2 rounded-full hover:bg-white/5"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            {/* Chat Area */}
            <div
              ref={scrollRef}
              className="flex-1 overflow-y-auto p-4 space-y-4 scroll-smooth"
            >
              {messages.map((msg, idx) => (
                <div
                  key={idx}
                  className={cn(
                    "flex flex-col max-w-[85%]",
                    msg.role === 'user' ? "ml-auto items-end" : "mr-auto items-start"
                  )}
                >
                  <div className={cn(
                    "px-4 py-2.5 rounded-2xl text-sm leading-relaxed",
                    msg.role === 'user'
                      ? "bg-primary text-primary-foreground rounded-br-sm"
                      : "bg-surface-variant/50 text-on-surface border border-outline-variant/30 rounded-bl-sm"
                  )}>
                    {msg.content}
                  </div>
                  <span className="text-[10px] text-on-surface-variant font-medium mt-1 uppercase tracking-wider px-1">
                    {msg.role === 'user' ? 'You' : 'A4 Explainer'}
                  </span>
                </div>
              ))}

              {isTyping && (
                <div className="mr-auto flex flex-col items-start max-w-[85%]">
                  <div className="px-4 py-3 rounded-2xl rounded-bl-sm bg-surface-variant/50 border border-outline-variant/30 text-on-surface flex items-center gap-2">
                    <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-1.5 h-1.5 bg-primary rounded-full animate-bounce"></div>
                  </div>
                </div>
              )}
            </div>

            {/* Input Area */}
            <form
              onSubmit={handleSubmit}
              className="p-3 border-t border-outline-variant/30 bg-surface/50 backdrop-blur-md"
            >
              <div className="relative flex items-center">
                <input
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="Ask why a transaction was flagged..."
                  className="w-full bg-surface-variant/30 border border-outline-variant/40 rounded-full py-2.5 pl-4 pr-[3.25rem] text-sm text-on-surface placeholder:text-on-surface-variant/50 focus:outline-none focus:border-primary/50 focus:bg-surface-variant/50 transition-colors"
                />
                <button
                  type="submit"
                  disabled={!query.trim() || isTyping}
                  className="absolute right-1.5 w-8 h-8 flex items-center justify-center rounded-full bg-primary text-primary-foreground disabled:opacity-50 disabled:cursor-not-allowed hover:bg-primary-dark transition-colors"
                >
                  <Send className="w-4 h-4 ml-0.5" />
                </button>
              </div>
              <p className="text-center text-[10px] text-on-surface-variant mt-2">AI can make mistakes. Check important rules.</p>
            </form>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  }
)
Button.displayName = "Button"

export { Button, buttonVariants }

import React, { useState, useCallback } from "react";
import { UploadCloud, FileType, CheckCircle, X, FileSpreadsheet, FileText, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";
import { Link } from "react-router-dom";


export function FileUpload({ onUploadComplete }: { onUploadComplete?: (file: File, auditResults: any, documentId: number) => void }) {
    const [isDragging, setIsDragging] = useState(false);
    const [file, setFile] = useState<File | null>(null);
    const [uploadState, setUploadState] = useState<'idle' | 'uploading' | 'success' | 'error'>('idle');
    const [errorMessage, setErrorMessage] = useState("");

    const allowedTypes = ["application/pdf", "text/csv", "application/vnd.ms-excel", "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"];
    const maxSizeBytes = 10 * 1024 * 1024; // 10MB

    const handleDragOver = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(true);
    }, []);

    const handleDragLeave = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
    }, []);

    const validateFile = (selectedFile: File) => {
        if (!allowedTypes.includes(selectedFile.type)) {
            setErrorMessage("Only PDF, CSV, and XLS/XLSX files are supported.");
            return false;
        }
        if (selectedFile.size > maxSizeBytes) {
            setErrorMessage("File exceeds the 10MB limit.");
            return false;
        }
        return true;
    };

    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        setErrorMessage("");
        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            const selectedFile = e.dataTransfer.files[0];
            if (validateFile(selectedFile)) {
                startUpload(selectedFile);
            } else {
                setUploadState('error');
            }
        }
    }, []);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setErrorMessage("");
        if (e.target.files && e.target.files.length > 0) {
            const selectedFile = e.target.files[0];
            if (validateFile(selectedFile)) {
                startUpload(selectedFile);
            } else {
                setUploadState('error');
            }
        }
    };

    const startUpload = async (selectedFile: File) => {
        setFile(selectedFile);
        setUploadState('uploading');

        try {
            const { api } = await import("@/lib/api");
            const res = await api.uploadDocument(selectedFile);

            if (res.success) {
                const auditRes = await api.runAuditPipeline(res.document_id, res.extracted_text);
                setUploadState('success');
                if (onUploadComplete) onUploadComplete(selectedFile, auditRes, res.document_id);
            } else {
                console.error(res.error);
                setErrorMessage(res.error || "Upload failed");
                setUploadState('error');
            }
        } catch (e: any) {
            console.error(e);
            setErrorMessage(e.message || "An error occurred during upload.");
            setUploadState('error');
        }
    };

    const resetUpload = () => {
        setFile(null);
        setUploadState('idle');
        setErrorMessage("");
    };

    const getFileIcon = (fileType: string) => {
        if (fileType.includes("pdf")) return <FileText className="w-8 h-8 text-red-500" />;
        if (fileType.includes("csv") || fileType.includes("excel") || fileType.includes("spreadsheet")) return <FileSpreadsheet className="w-8 h-8 text-green-500" />;
        return <FileType className="w-8 h-8 text-blue-500" />;
    };

    return (
        <div className="w-full max-w-2xl mx-auto">
            <AnimatePresence mode="wait">
                {uploadState === 'idle' || uploadState === 'error' ? (
                    <motion.div
                        key="dropzone"
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        exit={{ opacity: 0, scale: 0.95 }}
                        className={cn(
                            "relative group glass-card glass-border rounded-3xl p-8 md:p-12 flex flex-col items-center justify-center border-2 border-dashed transition-all duration-300",
                            isDragging ? "border-primary bg-primary/5 shadow-[0_0_30px_rgba(59,130,246,0.15)]" : "border-outline-variant/40 hover:border-primary/50 hover:bg-surface-variant/30"
                        )}
                        onDragOver={handleDragOver}
                        onDragLeave={handleDragLeave}
                        onDrop={handleDrop}
                    >
                        <div className="absolute inset-0 z-0 bg-gradient-to-b from-transparent to-primary/5 opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-3xl pointer-events-none"></div>

                        <div className="relative z-10 flex flex-col items-center justify-center text-center space-y-4">
                            <div className="w-20 h-20 rounded-full bg-surface shadow-inner flex items-center justify-center mb-2 border border-outline-variant/30 group-hover:scale-110 transition-transform duration-500 ease-out">
                                <UploadCloud className="w-10 h-10 text-primary" />
                            </div>
                            <h3 className="text-2xl font-bold font-headline text-on-surface">Upload Documents</h3>
                            <p className="text-on-surface-variant max-w-sm">Drag and drop your financial documents here to initiate the AI compliance pipeline.</p>

                            <div className="flex items-center gap-2 pt-4">
                                <span className="px-3 py-1 rounded-full bg-red-500/10 text-red-400 text-xs font-semibold border border-red-500/20">PDF</span>
                                <span className="px-3 py-1 rounded-full bg-green-500/10 text-green-400 text-xs font-semibold border border-green-500/20">CSV</span>
                                <span className="px-3 py-1 rounded-full bg-blue-500/10 text-blue-400 text-xs font-semibold border border-blue-500/20">XLS</span>
                            </div>

                            {uploadState === 'error' && (
                                <div className="mt-4 p-3 bg-destructive/10 border border-destructive/20 rounded-lg text-destructive text-sm font-medium animate-in fade-in slide-in-from-bottom-2">
                                    {errorMessage}
                                </div>
                            )}

                            <div className="pt-6 relative">
                                <input
                                    type="file"
                                    id="fileUpload"
                                    className="hidden"
                                    accept=".pdf,.csv,.xls,.xlsx"
                                    onChange={handleFileChange}
                                />
                                <label
                                    htmlFor="fileUpload"
                                    className="px-6 py-3 rounded-full bg-primary hover:bg-primary-dark text-primary-foreground font-semibold cursor-pointer transition-colors shadow-lg shadow-primary/20 inline-flex items-center gap-2"
                                >
                                    Browse Files
                                </label>
                            </div>
                            <p className="text-xs text-on-surface-variant/70 mt-4">Max file size: 10MB</p>
                        </div>
                    </motion.div>
                ) : (
                    <motion.div
                        key="uploading-success"
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="glass-card glass-border rounded-3xl p-8 relative overflow-hidden flex flex-col items-center border border-outline-variant/30"
                    >
                        {uploadState === 'uploading' && <div className="absolute top-0 left-0 h-1 w-full bg-surface-variant overflow-hidden"><motion.div initial={{ width: "0%" }} animate={{ width: "100%" }} transition={{ duration: 3, ease: "linear" }} className="h-full bg-primary"></motion.div></div>}

                        <div className="flex flex-col items-center justify-center text-center space-y-6 pt-4">
                            <div className="relative">
                                {uploadState === 'uploading' ? (
                                    <div className="w-24 h-24 rounded-full bg-primary/10 flex items-center justify-center border-2 border-primary border-t-transparent animate-spin">
                                        <div className="w-20 h-20 rounded-full bg-surface flex items-center justify-center animate-none">
                                            {file && getFileIcon(file.type)}
                                        </div>
                                    </div>
                                ) : (
                                    <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: "spring", bounce: 0.5 }} className="w-24 h-24 rounded-full bg-green-500/10 flex items-center justify-center border 2 border-green-500/30">
                                        <CheckCircle className="w-12 h-12 text-green-500" />
                                    </motion.div>
                                )}
                            </div>

                            <div className="space-y-2">
                                <h3 className="text-xl font-bold font-headline text-on-surface">
                                    {uploadState === 'uploading' ? "Processing via AI Pipeline..." : "Analysis Complete"}
                                </h3>
                                <p className="text-on-surface-variant text-sm">
                                    {file?.name} ({(file?.size! / 1024 / 1024).toFixed(2)} MB)
                                </p>
                            </div>

                            {uploadState === 'uploading' ? (
                                <div className="w-full max-w-xs space-y-3 pt-4 text-sm text-left">
                                    <div className="flex items-center gap-3 text-on-surface"><Loader2 className="w-4 h-4 animate-spin text-primary" /> <span>A1: Document Parser (Gemini)</span></div>
                                    <div className="flex items-center gap-3 text-on-surface-variant opacity-70"><Loader2 className="w-4 h-4 text-transparent" /> <span>A2: Rule Extraction Agent</span></div>
