interface AuthComponentProps {
  logo?: React.ReactNode;
  brandName?: string;
  onContinueAsGuest?: () => void;
  onSuccess?: () => void;
}

export const AuthComponent = ({ logo = <DefaultLogo />, brandName = "AuditAI", onContinueAsGuest, onSuccess }: AuthComponentProps) => {
  const [authMode, setAuthMode] = useState<'login' | 'register'>('register');
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [authStep, setAuthStep] = useState<"choose" | "form">("choose");
  const [modalStatus, setModalStatus] = useState<'closed' | 'loading' | 'error' | 'success'>('closed');
  const [modalErrorMessage, setModalErrorMessage] = useState('');
  const confettiRef = useRef<ConfettiRef>(null);

  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isPasswordValid = password.length >= 6;
  const isConfirmPasswordValid = confirmPassword.length >= 6;

  const passwordInputRef = useRef<HTMLInputElement>(null);
  const confirmPasswordInputRef = useRef<HTMLInputElement>(null);

  const fireSideCanons = () => {
    const fire = confettiRef.current?.fire;
    if (fire) {
        const defaults = { startVelocity: 30, spread: 360, ticks: 60, zIndex: 100 };
        const particleCount = 50;
        fire({ ...defaults, particleCount, origin: { x: 0, y: 1 }, angle: 60 });
        fire({ ...defaults, particleCount, origin: { x: 1, y: 1 }, angle: 120 });
    }
  };

  const handleFinalSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (modalStatus !== 'closed') return;

    if (!isEmailValid || !isPasswordValid) {
        setModalErrorMessage("Please fill all fields correctly.");
        setModalStatus('error');
        return;
    }

    if (authMode === 'register') {
      if (!isConfirmPasswordValid || password !== confirmPassword) {
          setModalErrorMessage("Passwords do not match!");
          setModalStatus('error');
          return;
      }
    }

    setModalStatus('loading');
    const loadingStepsCount = modalSteps.length - 1;
    const totalDuration = loadingStepsCount * TEXT_LOOP_INTERVAL * 1000;
    setTimeout(() => {
        fireSideCanons();
        setModalStatus('success');
        setTimeout(() => {
            if (onSuccess) {
                onSuccess();
            } else if (onContinueAsGuest) {
                onContinueAsGuest();
            }
        }, 3000);
    }, totalDuration);
  };

  const handleModeSelect = (mode: 'login' | 'register') => {
      setAuthMode(mode);
      setAuthStep("form");
  };



  const handleGoBack = () => {
    if (authStep === 'form') {
        setAuthStep('choose');
        setEmail('');
        setPassword('');
        setConfirmPassword('');
    }
  };

  const closeModal = () => {
    setModalStatus('closed');
    setModalErrorMessage('');
  };

  // No autofocus timeouts are strictly needed now.

  useEffect(() => {
      if (modalStatus === 'success') {
          fireSideCanons();
      }
  }, [modalStatus]);

  const Modal = () => (
    <AnimatePresence>
        {modalStatus !== 'closed' && (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
                <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }} className="relative bg-[#1A1818] border-4 border-[#333333] rounded-2xl p-8 w-full max-w-sm flex flex-col items-center gap-4 mx-2">
