import React, { createContext, useContext, useState } from 'react';

interface AppContextType {
  hasUploadedData: boolean;
  setHasUploadedData: (val: boolean) => void;
  documentId: number | null;
  setDocumentId: (val: number | null) => void;
  auditResults: any | null;
  setAuditResults: (val: any | null) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export function AppProvider({ children }: { children: React.ReactNode }) {
  const [hasUploadedData, setHasUploadedData] = useState(false);
  const [documentId, setDocumentId] = useState<number | null>(null);
  const [auditResults, setAuditResults] = useState<any | null>(null);

  return (
    <AppContext.Provider value={{ hasUploadedData, setHasUploadedData, documentId, setDocumentId, auditResults, setAuditResults }}>
      {children}
    </AppContext.Provider>
  );
}

export function useAppContext() {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useAppContext must be used within an AppProvider');
  }
  return context;
}

import React, { useState, useRef, useEffect } from "react";
import { MessageSquare, Send, Bot, User, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";

import { useAppContext } from "@/context/AppContext";
import { api } from "@/lib/api";

export default function Chat() {
  const { documentId } = useAppContext();
  const [query, setQuery] = useState("");
  const [messages, setMessages] = useState<{ role: 'user' | 'ai', content: string }[]>([
    { role: 'ai', content: "Hello! I'm your Explanation Agent powered by Llama 3. Ask me about any flagged transaction or compliance rule." }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    const userQuery = query.trim();
    setMessages(prev => [...prev, { role: 'user', content: userQuery }]);
    setQuery("");
    setIsTyping(true);

    try {
      const res = await api.askChatbot(userQuery, documentId);
      setMessages(prev => [...prev, { role: 'ai', content: res.answer }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'ai', content: "Error communicating with Explanation Agent. Is the backend running?" }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="w-full h-full p-4 md:p-8 xl:p-12 mb-20 max-w-5xl mx-auto flex flex-col h-[calc(100vh-100px)]">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-8 flex-shrink-0">
        <div>
          <h1 className="text-3xl md:text-4xl font-bold font-headline text-on-surface tracking-tight mb-2 flex items-center gap-3">
            <Bot className="w-8 h-8 text-green-500" />
            Explanation Agent
          </h1>
          <p className="text-on-surface-variant max-w-2xl">Ask the A4 AI Chatbot to explain any flagged anomaly, policy rule, or penalty risk in plain English. Powered by Groq & Llama 3.</p>
        </div>
      </div>

      <div className="flex-1 glass-card glass-border rounded-2xl flex flex-col overflow-hidden shadow-[0_10px_40px_rgba(0,0,0,0.5)] bg-surface/40 backdrop-blur-2xl border border-outline-variant/30 min-h-[400px]">
        {/* Chat Area */}
        <div
          ref={scrollRef}
          className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 scroll-smooth"
        >
          {messages.map((msg, idx) => (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              key={idx}
              className={cn(
                "flex flex-col max-w-[85%] md:max-w-[70%]",
